import requests

def solve(arg1: dict) -> dict:
    url = arg1.get('url')
    method = arg1.get('method', 'GET')

    if method == 'GET':
        try:
            response = requests.get(url, timeout=5)
            if response.status_code == 200:
                return {'status': 200, 'data': 'valid response'}
            else:
                return {'status': 'error', 'message': 'invalid response'}
        except requests.exceptions.Timeout:
            return {'status': 'error', 'message': 'timeout'}
        except requests.exceptions.SSLError:
            return {'status': 'error', 'message': 'invalid certificate'}
    elif method == 'POST':
        # Placeholder for POST logic if needed
        pass

    return {'status': 'error', 'message': 'unsupported method'}
